import logo from "./logo.svg";
import "./App.css";
import Typewriter from "typewriter-effect";

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <h1>
          <Typewriter
            onInit={(typewriter) => {
              const loopTyping = () => {
                typewriter
                  .typeString("Hello, I'm Burgeon, a web dev")
                  .callFunction(() => {
                    console.log("String typed out!");
                  })
                  .pauseFor(1000)
                  .deleteAll()
                  .callFunction(() => {
                    console.log("All strings were deleted");
                  })
                  .callFunction(loopTyping) // Calls loopTyping again to create a loop
                  .start();
              };

              loopTyping(); // Start the loop
            }}
          />
        </h1>

        <Navbar />
      </header>
    </div>
  );
}

export default App;

const Profile = () => {
  return (
    <>
      <div>
        <img src="#" alt="burgeon" className="display-pic" />
        <h1>
          Hello <span>I'm Burgeon</span>
        </h1>
      </div>
    </>
  );
};
const Navbar = () => {};
